// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/// @title ParametricInsurance
/// @notice Minimal demo vault combining purchase and owner-triggered payouts.
/// @dev Owner acts as a trusted operator; kept for comparison with modular Policy/Treasury.
contract ParametricInsurance is Ownable, ReentrancyGuard {
    // Mapping of insured address to nominal coverage units (simple example: equals paid premium)
    mapping(address => uint256) public coverageAmountOf;

    // Total premiums collected (accounting variable)
    uint256 public totalPremiums;

    event PolicyPurchased(address indexed purchaser, uint256 premium, uint256 coverageUnits);
    event PayoutTriggered(bytes32 indexed eventId, address indexed recipient, uint256 amount);
    event SurplusWithdrawn(address indexed to, uint256 amount);

    constructor(address initialOwner) Ownable(initialOwner) {}

    /// @notice Buy coverage by paying a premium in ETH; simple 1:1 coverage for demo purposes
    function purchasePolicy() external payable {
        require(msg.value > 0, "Premium required");
        coverageAmountOf[msg.sender] += msg.value;
        totalPremiums += msg.value;
        emit PolicyPurchased(msg.sender, msg.value, msg.value);
    }

    /// @notice Owner-triggered payout to a recipient when the parametric condition is met
    /// @param recipient Address to receive the payout
    /// @param amount Amount of ETH to pay
    /// @param eventId Identifier of the triggering event/condition (off-chain correlation)
    function triggerPayout(address recipient, uint256 amount, bytes32 eventId)
        external
        onlyOwner
        nonReentrant
    {
        require(recipient != address(0), "Invalid recipient");
        require(amount > 0, "Amount=0");
        require(address(this).balance >= amount, "Insufficient funds");

        // Note: For simplicity, we do not reduce recipient's coverage in this demo contract.
        // A production version would track policy states, coverage limits, epochs, etc.
        (bool sent, ) = payable(recipient).call{value: amount}("");
        require(sent, "Transfer failed");

        emit PayoutTriggered(eventId, recipient, amount);
    }

    /// @notice Withdraw surplus funds from the contract (e.g., to insurer treasury)
    function withdrawSurplus(address to, uint256 amount) external onlyOwner nonReentrant {
        require(to != address(0), "Invalid to");
        require(amount > 0, "Amount=0");
        require(address(this).balance >= amount, "Insufficient funds");
        (bool sent, ) = payable(to).call{value: amount}("");
        require(sent, "Transfer failed");
        emit SurplusWithdrawn(to, amount);
    }

    /// @notice Accept direct ETH top-ups (e.g., to pre-fund the pool)
    receive() external payable {}
}

contracts/Policy.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@chainlink/contracts/src/v0.8/ChainlinkClient.sol";

/// @title ITreasury Interface
/// @notice Interface for the Treasury contract that manages funds
interface ITreasury {
    function deposit() external payable;
    function transferOut(address to, uint256 amount) external;
    function getBalance() external view returns (uint256);
    function setPolicy(address policyAddress) external;
    function increaseReserve(uint256 amount) external;
    function decreaseReserve(uint256 amount) external;
}

/// @title Policy
/// @notice Main contract for parametric insurance policies. Handles policy creation,
///         management, and payout execution based on oracle-provided triggers.
/// @dev Integrates with Chainlink for external data and Treasury for fund management
contract Policy is Ownable, ReentrancyGuard, Pausable, ChainlinkClient {
    // --------- Custom Errors ---------
    error PremiumRequired();      // Premium payment missing
    error PayoutRequired();       // Payout amount not specified
    error PayoutExceedsMax();     // Payout exceeds maximum allowed
    error NotAuthorized();        // Caller not authorized
    error PolicyNotFound();       // Policy ID does not exist
    error NotActive();            // Policy is not active
    error AlreadyTriggered();     // Policy already triggered
    error AlreadyPaid();         // Payout already executed
    error InsufficientFunds();    // Not enough funds in treasury
    error InvalidOracle();        // Invalid oracle address
    error InvalidLink();          // Invalid LINK token address
    /// @notice Structure holding policy details
    /// @dev All monetary values are in wei
    struct PolicyData {
        uint256 id;              // Unique policy identifier
        address policyholder;    // Address of the policy owner
        uint256 premium;         // Amount paid to purchase policy
        uint256 payout;         // Amount to be paid if triggered
        uint256 threshold;      // Trigger threshold (e.g., rainfall in mm)
        bool active;            // Whether policy is active
        bool triggered;         // Whether policy has been triggered
    }

    // policyId → Policy
    mapping(uint256 => PolicyData) public policies;

    // address → array of user policy IDs
    mapping(address => uint256[]) public userPolicyIds;

    // Tracks whether a payout has been executed for a given policy id
    mapping(uint256 => bool) public payoutExecuted;

    // Next policy identifier
    uint256 public nextPolicyId;

    // Treasury contract that holds funds
    ITreasury public treasury;

    // --------- Storage ---------
    address public oracle;
    uint256 public maxPayout;
    mapping(bytes32 => uint256) public requestToPolicy;

    // --------- Chainlink Configuration ---------
    address public linkToken;
    bytes32 public jobId;
    uint256 public fee;

    // --------- Events ---------
    event OracleRequested(uint256 indexed policyId, bytes32 indexed requestId);
    event OracleFulfilled(bytes32 indexed requestId, uint256 value);
    event PolicyPurchased(uint256 indexed policyId, address indexed policyholder, uint256 premium, uint256 payout);
    event PolicyTriggered(uint256 indexed policyId);
    event PayoutExecuted(uint256 indexed policyId, address indexed to, uint256 amount);

    /// @notice Sets up the policy contract with treasury integration
    /// @param initialOwner Address of the contract owner
    /// @param treasuryAddress Address of the treasury contract
    constructor(address initialOwner, ITreasury treasuryAddress) Ownable(initialOwner) {
        require(address(treasuryAddress) != address(0), "Treasury required");
        treasury = treasuryAddress;
        // Authorization of this Policy in Treasury must be set by the Treasury owner externally.
        maxPayout = type(uint256).max;
        // Chainlink client will be configured later via setChainlinkParams
    }

    /// @notice Sets the oracle address for policy triggers
    /// @param oracleAddress Address of the oracle contract
    function setOracle(address oracleAddress) external onlyOwner {
        if (oracleAddress == address(0)) revert InvalidOracle();
        oracle = oracleAddress;
    }

    /// @notice Configures Chainlink oracle parameters
    /// @param linkTokenAddress Address of the LINK token
    /// @param oracleAddress Address of the Chainlink oracle
    /// @param job Chainlink job ID
    /// @param feeJuels Fee in LINK juels for oracle requests
    function setChainlinkParams(
        address linkTokenAddress,
        address oracleAddress,
        bytes32 job,
        uint256 feeJuels
    ) external onlyOwner {
        if (linkTokenAddress == address(0)) revert InvalidLink();
        if (oracleAddress == address(0)) revert InvalidOracle();
        linkToken = linkTokenAddress;
        oracle = oracleAddress;
        jobId = job;
        fee = feeJuels;
        setChainlinkToken(linkTokenAddress);
        setChainlinkOracle(oracleAddress);
    }

    /// @notice Sets maximum allowed payout per policy
    /// @param newMax New maximum payout amount
    function setMaxPayout(uint256 newMax) external onlyOwner {
        require(newMax > 0, "maxPayout=0");
        maxPayout = newMax;
    }

    /// @notice Pauses the contract
    function pause() external onlyOwner {
        _pause();
    }

    /// @notice Unpauses the contract
    function unpause() external onlyOwner {
        _unpause();
    }

    /// @notice Purchases a new parametric insurance policy
    /// @param payout Amount to be paid if policy is triggered
    /// @param threshold Condition that triggers the policy (e.g., rainfall amount)
    function buyPolicy(uint256 payout, uint256 threshold) external payable whenNotPaused {
        if (msg.value == 0) revert PremiumRequired();
        if (payout == 0) revert PayoutRequired();
        if (payout > maxPayout) revert PayoutExceedsMax();

        uint256 policyId = nextPolicyId;
        policies[policyId] = PolicyData({
            id: policyId,
            policyholder: msg.sender,
            premium: msg.value,
            payout: payout,
            threshold: threshold,
            active: true,
            triggered: false
        });

        userPolicyIds[msg.sender].push(policyId);
        nextPolicyId += 1;

        // CEI: Effects done, now interactions
        treasury.deposit{value: msg.value}();
        treasury.increaseReserve(payout);

        emit PolicyPurchased(policyId, msg.sender, msg.value, payout);
    }

    /// @notice Requests an oracle check for policy trigger conditions
    /// @param policyId ID of the policy to check
    /// @param apiUrl URL endpoint for oracle to fetch data
    /// @return requestId Chainlink request identifier
    function requestTriggerCheck(uint256 policyId, string calldata apiUrl) 
        external 
        onlyOwner 
        returns (bytes32 requestId) 
    {
        if (policies[policyId].policyholder == address(0)) revert PolicyNotFound();
        Chainlink.Request memory req = buildChainlinkRequest(
            jobId,
            address(this),
            this.fulfill.selector
        );
        // Add API parameters here
        requestId = sendChainlinkRequestTo(oracle, req, fee);
        requestToPolicy[requestId] = policyId;
        emit OracleRequested(policyId, requestId);
    }

    /// @notice Triggers a policy manually (owner/oracle only)
    /// @param policyId ID of the policy to trigger
    function triggerPolicy(uint256 policyId) external {
        if (msg.sender != owner() && msg.sender != oracle) revert NotAuthorized();
        PolicyData storage p = policies[policyId];
        if (p.policyholder == address(0)) revert PolicyNotFound();
        if (!p.active) revert NotActive();
        if (p.triggered) revert AlreadyTriggered();

        p.triggered = true;
        emit PolicyTriggered(policyId);

        executePayout(policyId);
    }

    /// @notice Chainlink callback for oracle responses
    /// @param requestId Chainlink request identifier
    /// @param value Data returned by the oracle
    function fulfill(bytes32 requestId, uint256 value) 
        public 
        recordChainlinkFulfillment(requestId) 
    {
        uint256 policyId = requestToPolicy[requestId];
        if (policies[policyId].policyholder == address(0)) revert PolicyNotFound();
        if (payoutExecuted[policyId]) revert AlreadyPaid();
        emit OracleFulfilled(requestId, value);

        if (value >= policies[policyId].threshold) {
            policies[policyId].triggered = true;
            emit PolicyTriggered(policyId);
            executePayout(policyId);
        }
        delete requestToPolicy[requestId];
    }

    /// @notice Internal function to execute policy payout
    /// @param policyId ID of the policy to pay out
    function executePayout(uint256 policyId) internal nonReentrant {
        PolicyData storage p = policies[policyId];
        if (p.policyholder == address(0)) revert PolicyNotFound();
        if (!(p.active && p.triggered)) revert NotActive();
        if (payoutExecuted[policyId]) revert AlreadyPaid();

        if (treasury.getBalance() < p.payout) revert InsufficientFunds();

        // CEI Pattern
        p.active = false;
        payoutExecuted[policyId] = true;

        // Interactions last
        treasury.decreaseReserve(p.payout);
        treasury.transferOut(p.policyholder, p.payout);

        emit PayoutExecuted(policyId, p.policyholder, p.payout);
    }

    /// @notice Gets all policies owned by a user
    /// @param user Address of the policyholder
    /// @return Array of policy data
    function getPoliciesByUser(address user) external view returns (PolicyData[] memory) {
        uint256[] storage ids = userPolicyIds[user];
        uint256 len = ids.length;
        PolicyData[] memory result = new PolicyData[](len);
        for (uint256 i = 0; i < len; i++) {
            result[i] = policies[ids[i]];
        }
        return result;
    }

    /// @notice Development helper to register mock oracle requests
    /// @param requestId Mock request identifier
    /// @param policyId ID of the policy to associate
    function mockRegisterRequest(bytes32 requestId, uint256 policyId) external onlyOwner {
        require(policies[policyId].policyholder != address(0), "Policy not found");
        addChainlinkExternalRequest(oracle, requestId);
        requestToPolicy[requestId] = policyId;
        emit OracleRequested(policyId, requestId);
    }
}

contracts/Treasury.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/// @title Treasury
/// @notice Holds ETH premiums and processes payouts. Integrates reserve accounting
///         to prevent withdrawing funds required for pending obligations.
contract Treasury is AccessControl, ReentrancyGuard {
    event Deposit(address indexed from, uint256 amount);
    event Withdraw(address indexed to, uint256 amount);
    event ReserveIncreased(uint256 amount, uint256 totalReserved);
    event ReserveDecreased(uint256 amount, uint256 totalReserved);

    bytes32 public constant POLICY_ROLE = keccak256("POLICY_ROLE");
    bytes32 public constant WITHDRAW_ROLE = keccak256("WITHDRAW_ROLE");

    // Reserved funds that should not be withdrawn via emergency or non-policy flows
    uint256 public totalReserved;

    constructor(address initialOwner) {
        require(initialOwner != address(0), "Invalid admin");
        _grantRole(DEFAULT_ADMIN_ROLE, initialOwner);
    }

    function deposit() external payable {
        require(msg.value > 0, "Amount=0");
        emit Deposit(msg.sender, msg.value);
    }

    function getBalance() external view returns (uint256) {
        return address(this).balance;
    }

    receive() external payable {
        emit Deposit(msg.sender, msg.value);
    }

    // Reserve management by Policy
    function increaseReserve(uint256 amount) external {
        require(hasRole(POLICY_ROLE, msg.sender), "Missing POLICY_ROLE");
        require(amount > 0, "Amount=0");
        uint256 balance = address(this).balance;
        uint256 available = balance > totalReserved ? balance - totalReserved : 0;
        require(available >= amount, "Insufficient liquidity");
        totalReserved += amount;
        emit ReserveIncreased(amount, totalReserved);
    }

    function decreaseReserve(uint256 amount) external {
        require(hasRole(POLICY_ROLE, msg.sender), "Missing POLICY_ROLE");
        require(amount > 0, "Amount=0");
        require(totalReserved >= amount, "Reserve underflow");
        totalReserved -= amount;
        emit ReserveDecreased(amount, totalReserved);
    }

    // Payouts can be initiated by callers with POLICY_ROLE or WITHDRAW_ROLE
    function transferOut(address payable to, uint256 amount) external nonReentrant {
        require(hasRole(POLICY_ROLE, msg.sender) || hasRole(WITHDRAW_ROLE, msg.sender), "Not authorized");
        require(to != address(0), "Invalid to");
        require(amount > 0, "Amount=0");
        require(address(this).balance >= amount, "Insufficient funds");
        (bool sent, ) = to.call{value: amount}("");
        require(sent, "Transfer failed");
        emit Withdraw(to, amount);
    }

    // Admin-only emergency withdraw that cannot touch reserved funds
    function emergencyWithdraw(address payable to, uint256 amount) external nonReentrant {
        require(hasRole(DEFAULT_ADMIN_ROLE, msg.sender), "Missing admin role");
        require(to != address(0), "Invalid to");
        require(amount > 0, "Amount=0");
        uint256 balance = address(this).balance;
        uint256 available = balance > totalReserved ? balance - totalReserved : 0;
        require(available >= amount, "Insufficient available liquidity");
        (bool sent, ) = to.call{value: amount}("");
        require(sent, "Transfer failed");
        emit Withdraw(to, amount);
    }

    // Backward-compat: optional helper to grant role when integrating legacy flows
    function setPolicy(address policyAddress) external {
        require(hasRole(DEFAULT_ADMIN_ROLE, msg.sender), "Missing admin role");
        require(policyAddress != address(0), "Invalid policy");
        _grantRole(POLICY_ROLE, policyAddress);
    }
}

